class Solution {
    public String lastSubstring(String s) {
        int n = s.length();
        int[] suffix = new int[n];
        suffix[0] = 0;
        int t = 1, k = 1;
        while (t < n) {
            if (s.charAt(t) == s.charAt(t - k)) {
                k++;
                suffix[t] = k;
                t++;
            } else if (s.charAt(t) < s.charAt(t - k)) {
                k = 1;
                suffix[t] = 0;
                t++;
            } else {
                k = suffix[t - k] + 1;
                suffix[t] = k;
                t++;
            }
        }
        int maxSuffix = 0;
        for (int i = 1; i < n; i++) {
            if (s.charAt(i) > s.charAt(maxSuffix)) {
                maxSuffix = i;
            } else if (s.charAt(i) == s.charAt(maxSuffix)) {
                int j = 1;
                while (i + j < n && s.charAt(i + j) == s.charAt(maxSuffix + j)) {
                    j++;
                }
                if (i + j < n && s.charAt(i + j) > s.charAt(maxSuffix + j)) {
                    maxSuffix = i;
                }
            }
        }
        return s.substring(maxSuffix);
    }
}
